from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a written work into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build simple phrase for each triple
    phrases = []
    for t in triples:
        # Convert predicate to a readable phrase (e.g., "numberOfPages" -> "has number of pages")
        pred = t.predicate
        # Simple heuristic: split camel case / underscores
        import re
        words = re.sub(r'(?<!^)(?=[A-Z])', ' ', pred).replace('_', ' ').lower()
        # Choose a connector based on common patterns
        if words in {"author", "publisher", "editor", "founder", "leader", "president", "headquarter", "parentcompany"}:
            phrase = f"{t.subject} is {words} {t.object}"
        elif words in {"isbnnumber", "issnnumber", "eissnnumber", "lccn number", "oclcnumber"}:
            phrase = f"The {words} of {t.subject} is {t.object}"
        elif words in {"language", "genre", "literarygenre", "media type", "country", "state", "city", "regionserved", "capital", "largestcity", "location", "family", "genus", "ethnicgroup", "demonym", "nickname", "leader title", "birthplace", "residence", "nationality"}:
            phrase = f"{t.subject} {words} {t.object}"
        elif words in {"followedby", "precededby"}:
            phrase = f"{t.subject} is {words} {t.object}"
        elif words in {"releasedate", "birthdate", "firstpublicationyear"}:
            phrase = f"{t.subject} was {words} {t.object}"
        elif words in {"number of pages"}:
            phrase = f"{t.subject} has {t.object} pages"
        else:
            phrase = f"{t.subject} {words} {t.object}"
        phrases.append(phrase)

    # Combine phrases into one sentence
    if len(phrases) == 1:
        sentence = phrases[0] + "."
    else:
        sentence = ", ".join(phrases[:-1]) + ", and " + phrases[-1] + "."
    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END
